## Security & Error Handling Review: `app.js`

### Current Issues

#### 1. 🔴 No Global Error Handler
If any route throws an unhandled error, Express will either crash or expose a stack trace to the client.

```js
// Add at the END, after all routes
app.use((err, req, res, next) => {
  console.error(err.stack); // Log internally
  res.status(500).json({ error: 'Internal Server Error' }); // Never expose err.message in production
});
```

#### 2. 🔴 No Security Headers (Missing `helmet`)
Without security headers, the app is vulnerable to XSS, clickjacking, MIME sniffing, etc.

```js
const helmet = require('helmet');
app.use(helmet()); // Sets X-Frame-Options, Content-Security-Policy, etc.
```

#### 3. 🔴 Sensitive Data Exposure on `/users`
The `/users` endpoint returns email addresses with no authentication or authorization check. Even with static data, this pattern is dangerous as the app grows.

```js
// At minimum, omit sensitive fields or gate behind auth middleware
app.get('/users', requireAuth, (req, res) => {
  res.json([
    { id: 1, name: 'Alice' }, // Don't expose email without need
    { id: 2, name: 'Bob' },
  ]);
});
```

#### 4. 🟡 No Rate Limiting
The endpoints are open to abuse (DoS, credential stuffing on future auth routes).

```js
const rateLimit = require('express-rate-limit');
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);
```

#### 5. 🟡 Hardcoded Port
Hardcoded ports are inflexible and can expose unintended interfaces in different environments.

```js
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});
```

#### 6. 🟡 No Request Body Parsing or Size Limits
If POST/PUT routes are ever added, there's no body parser or size cap — leaving the door open for payload-based attacks.

```js
app.use(express.json({ limit: '10kb' }));   // Reject oversized JSON
app.use(express.urlencoded({ extended: false, limit: '10kb' }));
```

#### 7. 🟡 No Input Validation Middleware
Future routes that accept query params or body input need validation. A library like `zod` or `express-validator` enforces schemas at the boundary.

```js
const { query, validationResult } = require('express-validator');

app.get('/users', query('id').optional().isInt({ min: 1 }), (req, res) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({ errors: errors.array() });
  }
  // ... proceed safely
});
```

#### 8. 🟢 No Access Logging
Without request logging, you have no audit trail for suspicious activity.

```js
const morgan = require('morgan');
app.use(morgan('combined')); // Or use a structured logger in production
```

---

### Suggested Revised `app.js`

```js
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const morgan = require('morgan');

const app = express();
const PORT = process.env.PORT || 3000;

// Security middleware
app.use(helmet());
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));
app.use(morgan('combined'));

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

// Routes
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // TODO: Add authentication/authorization middleware
  res.json([
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ]);
});

// 404 handler
app.use((req, res) => {
  res.status(404).json({ error: 'Not Found' });
});

// Global error handler (must have 4 params)
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production' ? 'Internal Server Error' : err.message,
  });
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
```

---

